import { useState } from "react";
import { Link } from "react-router-dom";
import mockUrunListesi from "../mock/mockUrunListesi";
import { Urun } from "../types/Urun";

const kategoriler = [
  {
    baslik: "Cep Telefonu-Aksesuar",
    altKategoriler: [
      "Apple Telefonlar",
      "Android Telefonlar",
      "Yapay Zeka (AI) Telefonlar",
      "Giyilebilir Teknolojiler",
      "Aksesuarlar"
    ],
  },
  {
    baslik: "Bilgisayar-Tablet",
    altKategoriler: ["Tabletler", "Dizüstü Bilgisayarlar"],
  },
  {
    baslik: "Elektrikli Ev Aletleri",
    altKategoriler: ["Süpürgeler", "Küçük Ev Aletleri"],
  },
];

export default function Kategoriler() {
  const [acilan, setAcilan] = useState<string | null>(null);

  return (
    <div className="flex gap-6 mt-4 relative overflow-x-auto whitespace-nowrap border-y py-2">
      {kategoriler.map((kat, i) => (
        <div
          key={i}
          className="relative group"
          onMouseEnter={() => setAcilan(kat.baslik)}
          onMouseLeave={() => setAcilan(null)}
        >
          <button className="font-semibold px-2 hover:text-yellow-600 transition">
            {kat.baslik}
          </button>

          {acilan === kat.baslik && (
            <div className="absolute left-0 top-full mt-2 bg-white shadow-lg border rounded z-50 w-[400px] p-4 grid grid-cols-2 gap-4">
              {kat.altKategoriler.map((alt, j) => {
                const altKategoriUrunleri = mockUrunListesi
                  .filter((u: Urun) => u.kategori === alt.toLowerCase())
                  .slice(0, 2);

                return (
                  <div key={j}>
                    <h4 className="font-semibold text-blue-600 mb-1">{alt}</h4>
                    <ul className="space-y-1 text-sm text-gray-700">
                      {altKategoriUrunleri.length === 0 ? (
                        <li className="text-gray-400">Ürün yok</li>
                      ) : (
                        altKategoriUrunleri.map((urun) => (
                          <li key={urun.id}>
                            <Link
                              to={`/urun/${urun.id}`}
                              className="hover:underline hover:text-blue-600"
                            >
                              {urun.ad}
                            </Link>
                          </li>
                        ))
                      )}
                    </ul>
                    <Link
                      to={`/kategori/${alt.toLowerCase()}`}
                      className="text-xs text-blue-500 hover:underline mt-1 inline-block"
                    >
                      Tümünü Gör
                    </Link>
                  </div>
                );
              })}
            </div>
          )}
        </div>
      ))}
    </div>
  );
}
